module RefModule(
    input clk,
    input rst,
    output reg [2:0] count
);reg [2:0] obf_next_count;

always @ (posedge clk) begin
    if (rst) begin
        count <= 3'b0;
    end
    else begin
        count <= obf_next_count;
    end
end

always @ (*) begin
    case (count)
        3'b000: obf_next_count = 3'b001;
        3'b001: obf_next_count = 3'b010;
        3'b010: obf_next_count = 3'b011;
        3'b011: obf_next_count = 3'b100;
        3'b100: obf_next_count = 3'b101;
        3'b101: obf_next_count = 3'b110;
        3'b110: obf_next_count = 3'b111;
        3'b111: obf_next_count = 3'b000;
        default: obf_next_count = 3'b0;
    endcase
end

endmodule
